  {
    "hypothesis_id": "H4",
    "hypothesis": "Full salary data (v1.1) was downloaded then forwarded externally to a headhunter",
    "supporting_evidence": [
      "Exact size match between downloaded v1.1 (2.3 MB) and emailed attachment (2.3 MB)",
      "Tight temporal correlation (41-minute gap) between download and external transmission",
      "Recipient domain belongs to a professional headhunting firm"
